const express = require('express');
const { requirePremium } = require('../middleware/auth');

const router = express.Router();

router.get('/premium', requirePremium, (req, res) => {
  res.json({
    data: "Premium dashboard content",
    customerId: req.headers['x-customer-id']
  });
});

