const express = require('express');
const dashboardRouter = require('./routes/dashboard');

const app = express();
const port = 3000;

app.use(express.json());
app.use('/dashboard', dashboardRouter);

app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});

module.exports = app;

